class Solution:
    def greatestLetter(self, s: str) -> str:
        lower = set()
        upper = set()
        for char in s:
            if char.islower():
                lower.add(char)
            else:
                upper.add(char)
        common = lower.intersection({char.lower() for char in upper})
        if common:
            return max(common).upper()
        return ""
```

